const App: React.FC = () => {
  const [characters, setCharacters] = useState<Character[]>([
    { id: 1, name: 'Character 1', image: null, mimeType: null, rotation: 0, isSelected: true },
    { id: 2, name: 'Character 2', image: null, mimeType: null, rotation: 0, isSelected: false },
    { id: 3, name: 'Character 3', image: null, mimeType: null, rotation: 0, isSelected: false },
    { id: 4, name: 'Character 4', image: null, mimeType: null, rotation: 0, isSelected: false },
  ]);
  const [style, setStyle] = useState<ImageStyle>(ImageStyle.ANIME);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ONE_ONE);
  const [prompts, setPrompts] = useState<string[]>(['Character 1 running in the park']);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImageResult[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSuggesting, setIsSuggesting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [storyName, setStoryName] = useState('MyFirstStory');
  const [seriesName, setSeriesName] = useState('MyFirstSeries');

  const [previewImage, setPreviewImage] = useState<string | null>(null);

  const handleUpdateCharacter = (updatedCharacter: Character) => {
    setCharacters(characters.map(c => c.id === updatedCharacter.id ? updatedCharacter : c));
  };

  const handleGenerateAll = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    setGeneratedImages([]);

    const selectedCharacters = characters.filter(c => c.isSelected && c.image && c.mimeType);
    if (selectedCharacters.length === 0) {
      setError('Please select at least one character with a reference image.');
      setIsLoading(false);
      return;
    }

    const referenceImages = selectedCharacters.map(c => ({
      data: c.image!,
      mimeType: c.mimeType!
    }));

    const results: GeneratedImageResult[] = [];
    for (const prompt of prompts) {
      if (!prompt.trim()) continue;
      try {
        const fullPrompt = `In a ${style} style, generate an image for the following scene: "${prompt}". Use the provided reference images to maintain character consistency. The characters are described as follows: ${selectedCharacters.map(c => c.name).join(', ')}.`;
        const imageData = await generateImageWithRetry(fullPrompt, referenceImages);
        if (imageData) {
          results.push({ id: crypto.randomUUID(), prompt, imageData });
          setGeneratedImages([...results]); // Update incrementally
        } else {
           setError(`Failed to generate image for prompt: "${prompt}"`);
        }
      } catch (e) {
        console.error(e);
        const errorMessage = e instanceof Error ? e.message : 'An unknown error occurred';
        setError(`An error occurred while generating images: ${errorMessage}`);
        break;
      }
    }

    setIsLoading(false);
  }, [characters, prompts, style]);

  const handleGenerateCharacter = useCallback(async (characterId: number) => {
      const character = characters.find(c => c.id === characterId);
      if (!character) return;

      setIsLoading(true);
      setError(null);
      try {
        const prompt = `Generate a character portrait of ${character.name}. Style: ${style}.`;
        const imageData = await generateImageWithRetry(prompt, []);
        if (imageData) {
            handleUpdateCharacter({
                ...character,
                image: imageData,
                mimeType: 'image/png'
            });
        } else {
            setError(`Failed to generate character ${character.name}`);
        }
      } catch (e) {
        console.error(e);
        const errorMessage = e instanceof Error ? e.message : 'An unknown error occurred';
        setError(`An error occurred while generating character: ${errorMessage}`);
      }
      setIsLoading(false);

  }, [characters, style]);

  const handleSuggestPrompt = useCallback(async () => {
    setIsSuggesting(true);
    try {
      const characterNames = characters.filter(c => c.isSelected).map(c => c.name);
      const newPrompt = await suggestCreativePrompt({
        storyName,
        seriesName,
        characters: characterNames,
        existingPrompts: prompts
      });
      setPrompts(prev => [...prev, newPrompt]);
    } catch (e) {
      console.error(e);
      setError("Failed to suggest a creative prompt.");
    } finally {
      setIsSuggesting(false);
    }
  }, [characters, storyName, seriesName, prompts]);


  return (
    <div className="min-h-screen bg-buzz-black font-sans flex flex-col">
      <Header />

      <main className="flex-grow flex flex-col lg:flex-row relative">
        <ControlPanel
          characters={characters}
          onUpdateCharacter={handleUpdateCharacter}
          onGenerateCharacter={handleGenerateCharacter}
          style={style}
          setStyle={setStyle}
          aspectRatio={aspectRatio}
          setAspectRatio={setAspectRatio}
          prompts={prompts}
          setPrompts={setPrompts}
          onGenerateAll={handleGenerateAll}
          onSuggestPrompt={handleSuggestPrompt}
          isLoading={isLoading}
          isSuggesting={isSuggesting}
          storyName={storyName}
          setStoryName={setStoryName}
          seriesName={seriesName}
          setSeriesName={setSeriesName}
        />
        <ResultsDisplay 
            images={generatedImages} 
            isLoading={isLoading} 
            error={error} 
            storyName={storyName}
            seriesName={seriesName}
            onPreview={setPreviewImage}
        />
      </main>

      {previewImage && (
        <div 
          className="fixed inset-0 bg-black/90 flex items-center justify-center z-50 p-4 backdrop-blur-sm"
          onClick={() => setPreviewImage(null)}
        >
          <div className="relative max-w-4xl max-h-[90vh] bg-gray-900 p-2 rounded-2xl shadow-2xl border border-bee-gold/20" onClick={e => e.stopPropagation()}>
             <img src={`data:image/png;base64,${previewImage}`} alt="Generated Preview" className="max-w-full max-h-[85vh] object-contain rounded-xl"/>
             <button
                onClick={() => setPreviewImage(null)}
                className="absolute -top-4 -right-4 bg-bee-gold text-buzz-black rounded-full p-2 hover:bg-bee-amber transition-transform duration-200 hover:scale-110 shadow-lg"
              >
               <XIcon />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export enum ImageStyle {
  USE_REFERENCE_ONE = 'Use reference image one',
  NINETIES_CARTOON = '90s Cartoon',
  ANIME = 'Anime',
  COMIC_HERO = 'Comic Hero',
  HYPER_REALISTIC = 'Hyper-Realistic',
  PHOTO_REALISTIC = 'Photo-Realistic'
}

export enum AspectRatio {
  SIXTEEN_NINE = '16:9',
  NINE_SIXTEEN = '9:16',
  ONE_ONE = '1:1',
  FOUR_THREE = '4:3',
  CUSTOM = 'Custom'
}

export interface Character {
  id: number;
  name: string;
  image: string | null;
  mimeType: string | null;
  rotation: number;
  isSelected: boolean;
  prompt: string;
}

export interface GeneratedImageResult {
  id: string;
  prompt: string;
  imageData: string;
  sceneIndex: number;
}

import { GoogleGenAI, Modality } from "@google/genai";

const MAX_RETRIES = 3;

export const generateImageWithRetry = async (prompt: string, referenceImages: { data: string, mimeType: string }[], styleReference?: { data: string, mimeType: string }): Promise<string | null> => {
    for (let i = 0; i < MAX_RETRIES; i++) {
        try {
            return await generateImage(prompt, referenceImages, styleReference);
        } catch (error) {
            console.error(`Attempt ${i + 1} failed:`, error);
            if (i === MAX_RETRIES - 1) {
                throw error;
            }
            await new Promise(res => setTimeout(res, 1000 * (i + 1))); // Exponential backoff
        }
    }
    return null;
};

const generateImage = async (prompt: string, referenceImages: { data: string, mimeType: string }[], styleReference?: { data: string, mimeType: string }): Promise<string | null> => {
  if (!process.env.API_KEY) {
    throw new Error("API_KEY environment variable not set");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const parts = [];

  if (styleReference) {
    parts.push({
        inlineData: {
          data: styleReference.data,
          mimeType: styleReference.mimeType,
        },
    });
    parts.push({ text: "Use the artistic style of the image above strictly as a visual reference for the generated output." });
  }

  parts.push(...referenceImages.map(img => ({
      inlineData: {
        data: img.data,
        mimeType: img.mimeType,
      },
  })));

  parts.push({ text: prompt });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts },
    config: {
      responseModalities: [Modality.IMAGE],
    },
  });

  for (const part of response.candidates?.[0]?.content?.parts ?? []) {
    if (part.inlineData) {
      return part.inlineData.data;
    }
  }

  return null;
};

export const suggestCreativePrompt = async (context: {
  storyName: string;
  seriesName: string;
  characters: string[];
  existingPrompts: string[];
  synopsis?: string;
}): Promise<string> => {
  if (!process.env.API_KEY) {
    throw new Error("API_KEY environment variable not set");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `You are a creative story boarding assistant for the series "${context.seriesName}".
  Synopsis: ${context.synopsis || "No synopsis provided."}
  Story: ${context.storyName}
  Characters: ${context.characters.join(', ')}
  Previous plot beats: ${context.existingPrompts.filter(p => p.trim()).join(' | ')}

  Suggest ONE creative, visually interesting image prompt for the NEXT scene in this sequence. 
  Focus on lighting, action, and cinematic placement. Keep it under 40 words. 
  Output ONLY the prompt text.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
  });

  return response.text?.trim() || "A cinematic scene featuring the characters.";
};

export const generateSynopsis = async (characters: string[]): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `Generate a riveting short storyline synopsis involving these characters: ${characters.join(', ')}. 
    If some are unnamed, give them interesting archetypes. Focus on drama and visual potential. Max 250 words.`;
    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
    });
    return response.text?.trim() || "A mysterious adventure begins...";
};

export const enhanceSynopsis = async (existing: string, characters: string[]): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `Rewrite and enhance the following synopsis to be more engaging, cinematic, and professional, providing more opportunity for story diversion and character development. 
    Characters: ${characters.join(', ')}
    Original: ${existing}
    Max 300 words.`;
    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
    });
    return response.text?.trim() || existing;
};

import React, { useState, useCallback } from 'react';
import { ControlPanel } from './components/ControlPanel';
import { ResultsDisplay } from './components/ResultsDisplay';
import { Header } from './components/Header';
import { XIcon } from './components/icons/XIcon';
import { Character, GeneratedImageResult, ImageStyle, AspectRatio } from './types';
import { generateImageWithRetry, suggestCreativePrompt, generateSynopsis, enhanceSynopsis } from './services/geminiService';

const INITIAL_CHARACTERS = ['One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight', 'Nine', 'Ten'];

const App: React.FC = () => {
  const [characters, setCharacters] = useState<Character[]>(
    INITIAL_CHARACTERS.map((name, i) => ({
      id: i + 1,
      name,
      image: null,
      mimeType: null,
      rotation: 0,
      isSelected: i < 4,
      prompt: ''
    }))
  );

  const [style, setStyle] = useState<ImageStyle>(ImageStyle.ANIME);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ONE_ONE);
  const [styleLocked, setStyleLocked] = useState(false);
  const [aspectRatioLocked, setAspectRatioLocked] = useState(false);

  const [prompts, setPrompts] = useState<string[]>(Array(6).fill(''));
  const [generatedImages, setGeneratedImages] = useState<GeneratedImageResult[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSuggesting, setIsSuggesting] = useState(false);
  const [loadingSlots, setLoadingSlots] = useState<Record<number, boolean>>({});
  const [error, setError] = useState<string | null>(null);

  const [storyName, setStoryName] = useState('NewStory');
  const [seriesName, setSeriesName] = useState('NewSeries');
  const [sceneNumber, setSceneNumber] = useState('1');
  const [synopsis, setSynopsis] = useState('');

  const [previewImage, setPreviewImage] = useState<string | null>(null);

  const handleUpdateCharacter = (updatedCharacter: Character) => {
    setCharacters(characters.map(c => c.id === updatedCharacter.id ? updatedCharacter : c));
  };

  const handleGenerateAll = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    setGeneratedImages([]);

    const selectedCharacters = characters.filter(c => c.isSelected && c.image && c.mimeType);
    if (selectedCharacters.length === 0) {
      setError('Please select at least one character with a reference image.');
      setIsLoading(false);
      return;
    }

    const referenceImages = selectedCharacters.map(c => ({
      data: c.image!,
      mimeType: c.mimeType!
    }));

    const styleRefChar = characters.find(c => c.id === 1);
    const styleRef = (style === ImageStyle.USE_REFERENCE_ONE && styleRefChar?.image) 
        ? { data: styleRefChar.image, mimeType: styleRefChar.mimeType! } 
        : undefined;

    const results: GeneratedImageResult[] = [];
    const activePrompts = prompts.filter(p => p.trim());

    for (let i = 0; i < activePrompts.length; i++) {
      const prompt = activePrompts[i];
      try {
        const fullPrompt = `${style !== ImageStyle.USE_REFERENCE_ONE ? `In a ${style} style, ` : ''}generate an image for the scene: "${prompt}". Consistent characters: ${selectedCharacters.map(c => c.name).join(', ')}. Story context: ${synopsis.slice(0, 200)}`;
        const imageData = await generateImageWithRetry(fullPrompt, referenceImages, styleRef);
        if (imageData) {
          results.push({ id: crypto.randomUUID(), prompt, imageData, sceneIndex: i + 1 });
          setGeneratedImages([...results]);
        }
      } catch (e) {
        setError(`Failed at scene ${i + 1}.`);
        break;
      }
    }
    setIsLoading(false);
  }, [characters, prompts, style, synopsis]);

  const handleGenerateCharacter = useCallback(async (characterId: number) => {
      const character = characters.find(c => c.id === characterId);
      if (!character) return;

      setLoadingSlots(prev => ({ ...prev, [characterId]: true }));
      setError(null);
      try {
        const promptText = character.prompt || `A character portrait of ${character.name}.`;
        const styleRefChar = characters.find(c => c.id === 1);
        const styleRef = (style === ImageStyle.USE_REFERENCE_ONE && styleRefChar?.image && characterId !== 1) 
            ? { data: styleRefChar.image, mimeType: styleRefChar.mimeType! } 
            : undefined;

        const prompt = `${style !== ImageStyle.USE_REFERENCE_ONE ? `Style: ${style}. ` : ''}${promptText}`;
        const imageData = await generateImageWithRetry(prompt, [], styleRef);
        if (imageData) {
            handleUpdateCharacter({
                ...character,
                image: imageData,
                mimeType: 'image/png'
            });
        }
      } catch (e) {
        setError(`Failed to generate character ${character.name}`);
      }
      setLoadingSlots(prev => ({ ...prev, [characterId]: false }));
  }, [characters, style]);

  const handleSuggestPrompt = useCallback(async () => {
    if (prompts.length >= 20) return;
    setIsSuggesting(true);
    try {
      const characterNames = characters.filter(c => c.isSelected).map(c => c.name);
      const newPrompt = await suggestCreativePrompt({
        storyName,
        seriesName,
        characters: characterNames,
        existingPrompts: prompts,
        synopsis
      });
      setPrompts(prev => [...prev, newPrompt]);
    } catch (e) {
      setError("Failed to suggest prompt.");
    } finally {
      setIsSuggesting(false);
    }
  }, [characters, storyName, seriesName, prompts, synopsis]);

  const handleGenerateSynopsis = async () => {
    setIsLoading(true);
    const chars = characters.filter(c => c.isSelected).map(c => c.name);
    const result = await generateSynopsis(chars);
    setSynopsis(result);
    setIsLoading(false);
  };

  const handleEnhanceSynopsis = async () => {
    setIsLoading(true);
    const chars = characters.filter(c => c.isSelected).map(c => c.name);
    const result = await enhanceSynopsis(synopsis, chars);
    setSynopsis(result);
    setIsLoading(false);
  };

  return (
    <div className="min-h-screen bg-black font-sans flex flex-col overflow-hidden">
      <Header />

      <div className="flex-1 flex flex-col">
        {/* TOP: Results Display */}
        <div className="h-1/2 overflow-y-auto border-b border-gray-800">
            <ResultsDisplay 
                images={generatedImages} 
                isLoading={isLoading} 
                error={error} 
                storyName={storyName}
                seriesName={seriesName}
                sceneNumber={sceneNumber}
                onPreview={setPreviewImage}
            />
        </div>

        {/* BOTTOM: Generations Setting */}
        <div className="h-1/2 bg-gray-900 overflow-y-auto">
            <ControlPanel
              characters={characters}
              loadingSlots={loadingSlots}
              onUpdateCharacter={handleUpdateCharacter}
              onGenerateCharacter={handleGenerateCharacter}
              style={style}
              setStyle={setStyle}
              aspectRatio={aspectRatio}
              setAspectRatio={setAspectRatio}
              styleLocked={styleLocked}
              setStyleLocked={setStyleLocked}
              aspectRatioLocked={aspectRatioLocked}
              setAspectRatioLocked={setAspectRatioLocked}
              prompts={prompts}
              setPrompts={setPrompts}
              onGenerateAll={handleGenerateAll}
              onSuggestPrompt={handleSuggestPrompt}
              isLoading={isLoading}
              isSuggesting={isSuggesting}
              storyName={storyName}
              setStoryName={setStoryName}
              seriesName={seriesName}
              setSeriesName={setSeriesName}
              sceneNumber={sceneNumber}
              setSceneNumber={setSceneNumber}
              synopsis={synopsis}
              setSynopsis={setSynopsis}
              onGenerateSynopsis={handleGenerateSynopsis}
              onEnhanceSynopsis={handleEnhanceSynopsis}
            />
        </div>
      </div>

      {previewImage && (
        <div 
          className="fixed inset-0 bg-black/90 flex items-center justify-center z-50 p-4 backdrop-blur-md"
          onClick={() => setPreviewImage(null)}
        >
          <div className="relative max-w-4xl max-h-[90vh] bg-gray-900 p-2 rounded-2xl shadow-2xl border border-bee-gold/20" onClick={e => e.stopPropagation()}>
             <img src={`data:image/png;base64,${previewImage}`} alt="Preview" className="max-w-full max-h-[85vh] object-contain rounded-xl"/>
             <button
                onClick={() => setPreviewImage(null)}
                className="absolute -top-4 -right-4 bg-bee-gold text-black rounded-full p-2 hover:bg-bee-amber transition-transform shadow-lg"
              >
               <XIcon />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Character, ImageStyle, AspectRatio } from '../types';
import { CharacterSlot } from './CharacterSlot';
import { PlusIcon } from './icons/PlusIcon';
import { TrashIcon } from './icons/TrashIcon';
import { SparklesIcon } from './icons/SparklesIcon';

interface ControlPanelProps {
  characters: Character[];
  loadingSlots: Record<number, boolean>;
  onUpdateCharacter: (character: Character) => void;
  onGenerateCharacter: (characterId: number) => void;
  style: ImageStyle;
  setStyle: (style: ImageStyle) => void;
  aspectRatio: AspectRatio;
  setAspectRatio: (ratio: AspectRatio) => void;
  styleLocked: boolean;
  setStyleLocked: (l: boolean) => void;
  aspectRatioLocked: boolean;
  setAspectRatioLocked: (l: boolean) => void;
  prompts: string[];
  setPrompts: (prompts: string[]) => void;
  onGenerateAll: () => void;
  onSuggestPrompt: () => void;
  isLoading: boolean;
  isSuggesting: boolean;
  storyName: string;
  setStoryName: (name: string) => void;
  seriesName: string;
  setSeriesName: (name: string) => void;
  sceneNumber: string;
  setSceneNumber: (n: string) => void;
  synopsis: string;
  setSynopsis: (s: string) => void;
  onGenerateSynopsis: () => void;
  onEnhanceSynopsis: () => void;
}

type Tab = 'General' | 'OutputSettings' | 'CastMembers' | 'ScenesList';

export const ControlPanel: React.FC<ControlPanelProps> = (props) => {
    const {
        characters, loadingSlots, onUpdateCharacter, onGenerateCharacter, style, setStyle, aspectRatio, setAspectRatio,
        styleLocked, setStyleLocked, aspectRatioLocked, setAspectRatioLocked,
        prompts, setPrompts, onGenerateAll, onSuggestPrompt, isLoading, isSuggesting,
        storyName, setStoryName, seriesName, setSeriesName, sceneNumber, setSceneNumber,
        synopsis, setSynopsis, onGenerateSynopsis, onEnhanceSynopsis
    } = props;

  const [activeTab, setActiveTab] = useState<Tab>('General');

  const handleAddPrompt = () => {
    if (prompts.length < 20) {
      setPrompts([...prompts, '']);
    }
  };

  const handleRemovePrompt = (index: number) => {
    setPrompts(prompts.filter((_, i) => i !== index));
  };

  const handlePromptChange = (index: number, value: string) => {
    const newPrompts = [...prompts];
    newPrompts[index] = value;
    setPrompts(newPrompts);
  };

  return (
    <div className="flex flex-col h-full bg-black">
      {/* Tab Headers */}
      <div className="flex border-b border-gray-800 bg-gray-950 px-4">
        {[
