const INITIAL_CHARACTERS = ['One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight', 'Nine', 'Ten'];

const App: React.FC = () => {
  const [characters, setCharacters] = useState<Character[]>(
    INITIAL_CHARACTERS.map((name, i) => ({
      id: i + 1,
      name,
      image: null,
      mimeType: null,
      rotation: 0,
      isSelected: i < 4,
      prompt: ''
    }))
  );

  const [style, setStyle] = useState<ImageStyle>(ImageStyle.ANIME);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ONE_ONE);
  const [styleLocked, setStyleLocked] = useState(false);
  const [aspectRatioLocked, setAspectRatioLocked] = useState(false);

  const [prompts, setPrompts] = useState<string[]>(Array(6).fill(''));
  const [promptActiveCharacterIds, setPromptActiveCharacterIds] = useState<number[]>([]);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImageResult[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSuggesting, setIsSuggesting] = useState(false);
  const [loadingSlots, setLoadingSlots] = useState<Record<number, boolean>>({});
  const [error, setError] = useState<string | null>(null);

  const [storyName, setStoryName] = useState('NewStory');
  const [seriesName, setSeriesName] = useState('NewSeries');
  const [sceneNumber, setSceneNumber] = useState('1');
  const [synopsis, setSynopsis] = useState('');

  const [previewImage, setPreviewImage] = useState<string | null>(null);

  const handleUpdateCharacter = (updatedCharacter: Character) => {
    setCharacters(characters.map(c => c.id === updatedCharacter.id ? updatedCharacter : c));
  };

  const handleGenerateAll = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    setGeneratedImages([]);

    const selectedCharacters = characters.filter(c => c.isSelected && c.image && c.mimeType);
    if (selectedCharacters.length === 0) {
      setError('Please select at least one character with a reference image.');
      setIsLoading(false);
      return;
    }

    const referenceImages = selectedCharacters.map(c => ({
      data: c.image!,
      mimeType: c.mimeType!
    }));

    const styleRefChar = characters.find(c => c.id === 1);
    const styleRef = (style === ImageStyle.USE_REFERENCE_ONE && styleRefChar?.image) 
        ? { data: styleRefChar.image, mimeType: styleRefChar.mimeType! } 
        : undefined;

    const results: GeneratedImageResult[] = [];
    const activePrompts = prompts.filter(p => p.trim());

    for (let i = 0; i < activePrompts.length; i++) {
      const prompt = activePrompts[i];
      try {
        const fullPrompt = `${style !== ImageStyle.USE_REFERENCE_ONE ? `In a ${style} style, ` : ''}generate an image for the scene: "${prompt}". Consistent characters: ${selectedCharacters.map(c => c.name).join(', ')}. Story context: ${synopsis.slice(0, 200)}`;
        const imageData = await generateImageWithRetry(fullPrompt, referenceImages, styleRef);
        if (imageData) {
          results.push({ id: crypto.randomUUID(), prompt, imageData, sceneIndex: i + 1 });
          setGeneratedImages([...results]);
        }
      } catch (e) {
        setError(`Failed at scene ${i + 1}.`);
        break;
      }
    }
    setIsLoading(false);
  }, [characters, prompts, style, synopsis]);

  const handleGenerateCharacter = useCallback(async (characterId: number) => {
      const character = characters.find(c => c.id === characterId);
      if (!character) return;

      setLoadingSlots(prev => ({ ...prev, [characterId]: true }));
      setError(null);
      try {
        const promptText = character.prompt || `A character portrait of ${character.name}.`;
        const styleRefChar = characters.find(c => c.id === 1);
        const styleRef = (style === ImageStyle.USE_REFERENCE_ONE && styleRefChar?.image && characterId !== 1) 
            ? { data: styleRefChar.image, mimeType: styleRefChar.mimeType! } 
            : undefined;

        const prompt = `${style !== ImageStyle.USE_REFERENCE_ONE ? `Style: ${style}. ` : ''}${promptText}`;
        const imageData = await generateImageWithRetry(prompt, [], styleRef);
        if (imageData) {
            handleUpdateCharacter({
                ...character,
                image: imageData,
                mimeType: 'image/png'
            });
        }
      } catch (e) {
        setError(`Failed to generate character ${character.name}`);
      }
      setLoadingSlots(prev => ({ ...prev, [characterId]: false }));
  }, [characters, style]);

  const handleSuggestSinglePrompt = useCallback(async (index: number) => {
    setIsSuggesting(true);
    try {
        const activeCharNames = characters.filter(c => promptActiveCharacterIds.includes(c.id)).map(c => c.name);
        const newPrompt = await suggestCreativePrompt({
            storyName,
            seriesName,
            characters: characters.map(c => c.name),
            activeCharacters: activeCharNames,
            existingPrompts: prompts,
            synopsis
        });
        const newPrompts = [...prompts];
        newPrompts[index] = newPrompt;
        setPrompts(newPrompts);
    } catch (e) {
        setError("Failed to suggest scene.");
    } finally {
        setIsSuggesting(false);
    }
  }, [characters, promptActiveCharacterIds, storyName, seriesName, prompts, synopsis]);

  const handleSuggestBulkPrompts = useCallback(async () => {
    setIsSuggesting(true);
    try {
        const emptyIndices = prompts.map((p, i) => p.trim() === '' ? i : -1).filter(i => i !== -1);
        if (emptyIndices.length === 0) return;

        const activeCharNames = characters.filter(c => promptActiveCharacterIds.includes(c.id)).map(c => c.name);
        const suggested = await suggestBulkScenes({
            storyName,
            seriesName,
            activeCharacters: activeCharNames,
            synopsis,
            count: emptyIndices.length,
            existingScenes: prompts
        });

        const newPrompts = [...prompts];
        emptyIndices.forEach((targetIdx, i) => {
            if (suggested[i]) newPrompts[targetIdx] = suggested[i];
        });
        setPrompts(newPrompts);
    } catch (e) {
        setError("Failed to populate scenes.");
    } finally {
        setIsSuggesting(false);
    }
  }, [characters, promptActiveCharacterIds, storyName, seriesName, prompts, synopsis]);

  const handleGenerateSynopsis = async () => {
    setIsLoading(true);
    const chars = characters.filter(c => c.isSelected).map(c => c.name);
    const result = await generateSynopsis(chars);
    setSynopsis(result);
    setIsLoading(false);
  };

  const handleEnhanceSynopsis = async () => {
    setIsLoading(true);
    const chars = characters.filter(c => c.isSelected).map(c => c.name);
    const result = await enhanceSynopsis(synopsis, chars);
    setSynopsis(result);
    setIsLoading(false);
  };

  return (
    <div className="min-h-screen bg-black font-sans flex flex-col overflow-hidden">
      <Header />

      <div className="flex-1 flex flex-col">
        {/* TOP: Results Display */}
        <div className="h-1/2 overflow-y-auto border-b border-gray-800">
            <ResultsDisplay 
                images={generatedImages} 
                isLoading={isLoading} 
                error={error} 
                storyName={storyName}
                seriesName={seriesName}
                sceneNumber={sceneNumber}
                onPreview={setPreviewImage}
            />
        </div>

        {/* BOTTOM: Generations Setting */}
        <div className="h-1/2 bg-gray-900 overflow-y-auto">
            <ControlPanel
              characters={characters}
              loadingSlots={loadingSlots}
              onUpdateCharacter={handleUpdateCharacter}
              onGenerateCharacter={handleGenerateCharacter}
              style={style}
              setStyle={setStyle}
              aspectRatio={aspectRatio}
              setAspectRatio={setAspectRatio}
              styleLocked={styleLocked}
              setStyleLocked={setStyleLocked}
              aspectRatioLocked={aspectRatioLocked}
              setAspectRatioLocked={setAspectRatioLocked}
              prompts={prompts}
              setPrompts={setPrompts}
              onGenerateAll={handleGenerateAll}
              onSuggestPrompt={handleSuggestBulkPrompts}
              onSuggestSinglePrompt={handleSuggestSinglePrompt}
              promptActiveCharacterIds={promptActiveCharacterIds}
              setPromptActiveCharacterIds={setPromptActiveCharacterIds}
              isLoading={isLoading}
              isSuggesting={isSuggesting}
              storyName={storyName}
              setStoryName={setStoryName}
              seriesName={seriesName}
              setSeriesName={setSeriesName}
              sceneNumber={sceneNumber}
              setSceneNumber={setSceneNumber}
              synopsis={synopsis}
              setSynopsis={setSynopsis}
              onGenerateSynopsis={handleGenerateSynopsis}
              onEnhanceSynopsis={handleEnhanceSynopsis}
            />
        </div>
      </div>

      {previewImage && (
        <div 
          className="fixed inset-0 bg-black/90 flex items-center justify-center z-50 p-4 backdrop-blur-md"
          onClick={() => setPreviewImage(null)}
        >
          <div className="relative max-w-4xl max-h-[90vh] bg-gray-900 p-2 rounded-2xl shadow-2xl border border-bee-gold/20" onClick={e => e.stopPropagation()}>
             <img src={`data:image/png;base64,${previewImage}`} alt="Preview" className="max-w-full max-h-[85vh] object-contain rounded-xl"/>
             <button
                onClick={() => setPreviewImage(null)}
                className="absolute -top-4 -right-4 bg-bee-gold text-black rounded-full p-2 hover:bg-bee-amber transition-transform shadow-lg"
              >
               <XIcon />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Character, ImageStyle, AspectRatio } from '../types';
import { CharacterSlot } from './CharacterSlot';
import { PlusIcon } from './icons/PlusIcon';
import { TrashIcon } from './icons/TrashIcon';
import { SparklesIcon } from './icons/SparklesIcon';

interface ControlPanelProps {
  characters: Character[];
  loadingSlots: Record<number, boolean>;
  onUpdateCharacter: (character: Character) => void;
  onGenerateCharacter: (characterId: number) => void;
  style: ImageStyle;
  setStyle: (style: ImageStyle) => void;
  aspectRatio: AspectRatio;
  setAspectRatio: (ratio: AspectRatio) => void;
  styleLocked: boolean;
  setStyleLocked: (l: boolean) => void;
  aspectRatioLocked: boolean;
  setAspectRatioLocked: (l: boolean) => void;
  prompts: string[];
  setPrompts: (prompts: string[]) => void;
  onGenerateAll: () => void;
  onSuggestPrompt: () => void;
  onSuggestSinglePrompt: (index: number) => void;
  promptActiveCharacterIds: number[];
  setPromptActiveCharacterIds: (ids: number[]) => void;
  isLoading: boolean;
  isSuggesting: boolean;
  storyName: string;
  setStoryName: (name: string) => void;
  seriesName: string;
  setSeriesName: (name: string) => void;
  sceneNumber: string;
  setSceneNumber: (n: string) => void;
  synopsis: string;
  setSynopsis: (s: string) => void;
  onGenerateSynopsis: () => void;
  onEnhanceSynopsis: () => void;
}

type Tab = 'General' | 'OutputSettings' | 'CastMembers' | 'ScenesList';

export const ControlPanel: React.FC<ControlPanelProps> = (props) => {
    const {
        characters, loadingSlots, onUpdateCharacter, onGenerateCharacter, style, setStyle, aspectRatio, setAspectRatio,
        styleLocked, setStyleLocked, aspectRatioLocked, setAspectRatioLocked,
        prompts, setPrompts, onGenerateAll, onSuggestPrompt, onSuggestSinglePrompt,
        promptActiveCharacterIds, setPromptActiveCharacterIds,
        isLoading, isSuggesting,
        storyName, setStoryName, seriesName, setSeriesName, sceneNumber, setSceneNumber,
        synopsis, setSynopsis, onGenerateSynopsis, onEnhanceSynopsis
    } = props;

  const [activeTab, setActiveTab] = useState<Tab>('General');

  const handleAddPrompt = () => {
    if (prompts.length < 20) {
      setPrompts([...prompts, '']);
    }
  };

  const handleRemovePrompt = (index: number) => {
    setPrompts(prompts.filter((_, i) => i !== index));
  };

  const handlePromptChange = (index: number, value: string) => {
    const newPrompts = [...prompts];
    newPrompts[index] = value;
    setPrompts(newPrompts);
  };

  const togglePromptActiveChar = (id: number) => {
      if (promptActiveCharacterIds.includes(id)) {
          setPromptActiveCharacterIds(promptActiveCharacterIds.filter(i => i !== id));
      } else {
          setPromptActiveCharacterIds([...promptActiveCharacterIds, id]);
      }
  };

  return (
    <div className="flex flex-col h-full bg-black">
      {/* Mobile Render Button Section */}
      <div className="md:hidden p-4 border-b border-gray-800">
        <button
            onClick={onGenerateAll}
            disabled={isLoading}
            style={{ backgroundColor: '#55DDE0' }}
            className="w-full text-black font-black text-sm py-3 rounded-full hover:brightness-110 transition-all disabled:opacity-50 uppercase tracking-widest shadow-lg"
        >
            {isLoading ? 'RENDERING...' : 'RENDER'}
        </button>
      </div>

      {/* Tab Headers - Made compact for mobile */}
      <div className="flex border-b border-gray-800 bg-gray-950 overflow-x-auto no-scrollbar sticky top-0 z-20">
        {[
          { id: 'General', label: 'General' },
          { id: 'OutputSettings', label: 'Output Settings' },
          { id: 'CastMembers', label: 'Cast Members' },
          { id: 'ScenesList', label: 'Scenes List' }
        ].map(t => (
          <button
            key={t.id}
            onClick={() => setActiveTab(t.id as Tab)}
            className={`flex-1 min-w-fit px-3 py-4 text-[10px] md:text-sm font-bold uppercase tracking-widest transition-all whitespace-nowrap ${
              activeTab === t.id 
                ? 'text-bee-gold border-b-2 border-bee-gold' 
                : 'text-gray-500 hover:text-gray-300'
            }`}
          >
            {t.label}
          </button>
        ))}
        {/* Desktop RENDER Button */}
        <div className="hidden md:flex ml-auto items-center pr-6">
            <button
                onClick={onGenerateAll}
                disabled={isLoading}
                style={{ backgroundColor: '#55DDE0' }}
                className="text-black font-black text-[10px] px-8 py-2 rounded-full hover:brightness-110 transition-all disabled:opacity-50 uppercase tracking-widest"
            >
                {isLoading ? 'RENDERING...' : 'RENDER'}
            </button>
        </div>
      </div>

      {/* Tab Content */}
      <div className="flex-1 p-4 md:p-8 overflow-y-auto">
        {activeTab === 'General' && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-5xl mx-auto">
            <div className="space-y-6">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black uppercase text-gray-500 mb-1 tracking-widest">Series Name</label>
                  <input value={seriesName} onChange={e => setSeriesName(e.target.value)} className="w-full bg-gray-900 border border-gray-800 rounded px-3 py-2 text-sm focus:ring-1 focus:ring-bee-gold outline-none"/>
                </div>
                <div>
                  <label className="block text-[10px] font-black uppercase text-gray-500 mb-1 tracking-widest">Story Name</label>
                  <input value={storyName} onChange={e => setStoryName(e.target.value)} className="w-full bg-gray-900 border border-gray-800 rounded px-3 py-2 text-sm focus:ring-1 focus:ring-bee-gold outline-none"/>
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black uppercase text-gray-500 mb-1 tracking-widest">Scene Number</label>
                <input type="number" value={sceneNumber} onChange={e => setSceneNumber(e.target.value)} className="w-full bg-gray-900 border border-gray-800 rounded px-3 py-2 text-sm focus:ring-1 focus:ring-bee-gold outline-none max-w-[120px]"/>
              </div>
            </div>
            <div className="space-y-3">
                <label className="block text-[10px] font-black uppercase text-gray-500 mb-1 tracking-widest">Synopsis</label>
                <textarea 
                    value={synopsis} 
                    onChange={e => setSynopsis(e.target.value.slice(0, 1500))} 
                    rows={6}
                    className="w-full bg-gray-900 border border-gray-800 rounded px-3 py-2 text-sm focus:ring-1 focus:ring-bee-gold outline-none resize-none leading-relaxed"
                    placeholder="Enter the overall narrative direction..."
                />
                <div className="flex flex-wrap gap-2">
                    <button onClick={onGenerateSynopsis} className="flex-1 min-w-fit px-4 py-2 bg-gray-800 text-[9px] font-black rounded hover:bg-gray-700 transition-colors uppercase tracking-widest">GENERATE STORYLINE</button>
                    <button onClick={onEnhanceSynopsis} className="flex-1 min-w-fit px-4 py-2 bg-gray-800 text-[9px] font-black rounded hover:bg-gray-700 transition-colors uppercase tracking-widest">ENHANCE STORY</button>
                </div>
            </div>
          </div>
        )}

        {activeTab === 'OutputSettings' && (
          <div className="flex flex-col md:flex-row gap-8 md:gap-12 max-w-4xl mx-auto items-start">
             <div className="space-y-4 w-full md:w-1/2">
                <div className="flex items-center justify-between">
                    <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest">Image Style</label>
                    <button onClick={() => setStyleLocked(!styleLocked)} className={`text-[10px] font-black ${styleLocked ? 'text-bee-gold' : 'text-gray-600'}`}>
                        {styleLocked ? 'LOCKED' : 'LOCK'}
                    </button>
                </div>
                <select 
                    disabled={styleLocked}
                    value={style} 
                    onChange={e => setStyle(e.target.value as ImageStyle)} 
                    className="w-full bg-gray-900 border border-gray-800 rounded px-3 py-2 text-sm focus:ring-1 focus:ring-bee-gold outline-none"
                >
                    {Object.values(ImageStyle).map(s => <option key={s} value={s}>{s}</option>)}
                </select>
             </div>
             <div className="space-y-4 w-full md:w-1/2">
                <div className="flex items-center justify-between">
                    <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest">Aspect Ratio</label>
                    <button onClick={() => setAspectRatioLocked(!aspectRatioLocked)} className={`text-[10px] font-black ${aspectRatioLocked ? 'text-bee-gold' : 'text-gray-600'}`}>
                        {aspectRatioLocked ? 'LOCKED' : 'LOCK'}
                    </button>
                </div>
                <select 
                    disabled={aspectRatioLocked}
                    value={aspectRatio} 
                    onChange={e => setAspectRatio(e.target.value as AspectRatio)} 
                    className="w-full bg-gray-900 border border-gray-800 rounded px-3 py-2 text-sm focus:ring-1 focus:ring-bee-gold outline-none"
                >
                    {Object.values(AspectRatio).map(r => <option key={r} value={r}>{r}</option>)}
                </select>
             </div>
          </div>
        )}

        {activeTab === 'CastMembers' && (
          <div className="grid grid-cols-2 md:flex md:overflow-x-auto gap-4 pb-4 px-1 no-scrollbar max-w-7xl mx-auto">
            {characters.map(char => (
                <div key={char.id} className="w-full md:min-w-[200px]">
                    <CharacterSlot 
                        character={char} 
                        isLoading={loadingSlots[char.id]}
                        onUpdate={onUpdateCharacter} 
                        onGenerate={onGenerateCharacter} 
                    />
                </div>
            ))}
          </div>
        )}

        {activeTab === 'ScenesList' && (
          <div className="max-w-6xl mx-auto space-y-8">
            {/* Active Characters Sub-window */}
            <div className="bg-gray-950/50 p-4 rounded-xl border border-gray-800">
                <h3 className="text-[10px] font-black uppercase text-gray-500 tracking-widest mb-4">Select Active Characters for Next Generation</h3>
                <div className="flex flex-wrap gap-2">
                    {characters.map(c => (
                        <button
                            key={c.id}
                            onClick={() => togglePromptActiveChar(c.id)}
                            className={`px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-tighter transition-all border ${
                                promptActiveCharacterIds.includes(c.id)
                                    ? 'bg-bee-gold text-black border-bee-gold'
                                    : 'bg-transparent text-gray-500 border-gray-800 hover:border-gray-600'
                            }`}
                        >
                            {c.name}
                        </button>
                    ))}
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-4">
                {prompts.map((prompt, index) => (
                    <div key={index} className="flex items-start space-x-3 bg-gray-950 p-3 rounded-lg border border-gray-800 hover:border-gray-700 transition-colors group relative">
                        <span className="text-bee-gold font-black text-[10px] mt-2 w-5">{String(index + 1).padStart(2, '0')}</span>
                        <textarea
                            value={prompt}
                            onChange={e => handlePromptChange(index, e.target.value)}
                            rows={2}
                            className="flex-grow bg-transparent text-sm focus:outline-none resize-none placeholder-gray-800"
                            placeholder="Describe the action..."
                        />
                        <div className="flex flex-col space-y-2 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button 
                                onClick={() => onSuggestSinglePrompt(index)} 
                                disabled={isSuggesting}
                                className="p-1.5 text-bee-gold/50 hover:text-bee-gold transition-colors" 
                                title="Magic Prompt"
                            >
                                <SparklesIcon className={`w-3.5 h-3.5 ${isSuggesting ? 'animate-pulse' : ''}`} />
                            </button>
                            <button 
                                onClick={() => handleRemovePrompt(index)} 
                                className="p-1.5 text-gray-700 hover:text-red-500 transition-colors" 
                                title="Remove"
                            >
                                <TrashIcon className="w-3.5 h-3.5" />
                            </button>
                        </div>
                    </div>
                ))}
            </div>

            <div className="flex flex-col sm:flex-row justify-center items-center gap-4 mt-8 pb-10">
                {prompts.length < 20 && (
                    <button 
                        onClick={handleAddPrompt} 
                        className="w-full sm:w-auto flex items-center justify-center space-x-2 py-3 px-10 border border-gray-800 rounded-full text-gray-500 hover:text-white hover:border-gray-600 transition-all text-[10px] font-black uppercase tracking-widest"
                    >
                        <PlusIcon className="w-3.5 h-3.5" />
                        <span>Add Scene</span>
                    </button>
                )}
                <button 
                    onClick={onSuggestPrompt}
                    disabled={isSuggesting || promptActiveCharacterIds.length === 0}
                    className="w-full sm:w-auto flex items-center justify-center space-x-2 py-3 px-10 bg-bee-gold/5 border border-bee-gold/20 text-bee-gold rounded-full hover:bg-bee-gold/10 transition-all text-[10px] font-black uppercase tracking-widest disabled:opacity-30"
                >
                    {isSuggesting ? (
                        <div className="w-3.5 h-3.5 border-2 border-bee-gold border-t-transparent rounded-full animate-spin"></div>
                    ) : (
                        <SparklesIcon className="w-3.5 h-3.5" />
                    )}
                    <span>Populate Scenes</span>
                </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { ControlPanel } from './components/ControlPanel';
import { ResultsDisplay } from './components/ResultsDisplay';
import { Header } from './components/Header';
import { XIcon } from './components/icons/XIcon';
import { Character, GeneratedImageResult, ImageStyle, AspectRatio } from './types';
import { generateImageWithRetry, suggestCreativePrompt, generateSynopsis, enhanceSynopsis, suggestBulkScenes } from './services/geminiService';

const INITIAL_CHARACTERS = ['One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight', 'Nine', 'Ten'];

const App: React.FC = () => {
  const [characters, setCharacters] = useState<Character[]>(
    INITIAL_CHARACTERS.map((name, i) => ({
      id: i + 1,
      name,
      image: null,
      mimeType: null,
      rotation: 0,
      isSelected: i < 4,
      prompt: ''
    }))
  );

  const [style, setStyle] = useState<ImageStyle>(ImageStyle.ANIME);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ONE_ONE);
  const [styleLocked, setStyleLocked] = useState(false);
  const [aspectRatioLocked, setAspectRatioLocked] = useState(false);

  const [prompts, setPrompts] = useState<string[]>(Array(6).fill(''));
  const [promptActiveCharacterIds, setPromptActiveCharacterIds] = useState<number[]>([]);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImageResult[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSuggesting, setIsSuggesting] = useState(false);
  const [loadingSlots, setLoadingSlots] = useState<Record<number, boolean>>({});
  const [error, setError] = useState<string | null>(null);

  const [storyName, setStoryName] = useState('NewStory');
  const [seriesName, setSeriesName] = useState('NewSeries');
  const [synopsis, setSynopsis] = useState('');

  const [previewImage, setPreviewImage] = useState<string | null>(null);

  const handleUpdateCharacter = (updatedCharacter: Character) => {
    setCharacters(characters.map(c => c.id === updatedCharacter.id ? updatedCharacter : c));
  };

  const handleGenerateAll = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    setGeneratedImages([]);

    const selectedCharacters = characters.filter(c => c.isSelected && c.image && c.mimeType);
    if (selectedCharacters.length === 0) {
      setError('Please select at least one character with a reference image.');
      setIsLoading(false);
      return;
    }

    const referenceImages = selectedCharacters.map(c => ({
      data: c.image!,
      mimeType: c.mimeType!
    }));

    const styleRefChar = characters.find(c => c.id === 1);
    const styleRef = (style === ImageStyle.USE_REFERENCE_ONE && styleRefChar?.image) 
        ? { data: styleRefChar.image, mimeType: styleRefChar.mimeType! } 
        : undefined;

    const results: GeneratedImageResult[] = [];
    const activePrompts = prompts.map((p, i) => ({ text: p, originalIndex: i + 1 })).filter(p => p.text.trim());

    for (let i = 0; i < activePrompts.length; i++) {
      const { text, originalIndex } = activePrompts[i];
      try {
        const fullPrompt = `${style !== ImageStyle.USE_REFERENCE_ONE ? `In a ${style} style, ` : ''}generate an image for the scene: "${text}". Consistent characters: ${selectedCharacters.map(c => c.name).join(', ')}. Story context: ${synopsis.slice(0, 200)}`;
        const imageData = await generateImageWithRetry(fullPrompt, referenceImages, styleRef);
        if (imageData) {
          results.push({ id: crypto.randomUUID(), prompt: text, imageData, sceneIndex: originalIndex });
          setGeneratedImages([...results]);
        }
      } catch (e) {
        setError(`Failed at scene ${originalIndex}.`);
        break;
      }
    }
    setIsLoading(false);
  }, [characters, prompts, style, synopsis]);

  const handleGenerateCharacter = useCallback(async (characterId: number) => {
      const character = characters.find(c => c.id === characterId);
      if (!character) return;

      setLoadingSlots(prev => ({ ...prev, [characterId]: true }));
      setError(null);
      try {
        const promptText = character.prompt || `A character portrait of ${character.name}.`;
        const styleRefChar = characters.find(c => c.id === 1);
        const styleRef = (style === ImageStyle.USE_REFERENCE_ONE && styleRefChar?.image && characterId !== 1) 
            ? { data: styleRefChar.image, mimeType: styleRefChar.mimeType! } 
            : undefined;

        const prompt = `${style !== ImageStyle.USE_REFERENCE_ONE ? `Style: ${style}. ` : ''}${promptText}`;
        const imageData = await generateImageWithRetry(prompt, [], styleRef);
        if (imageData) {
            handleUpdateCharacter({
                ...character,
                image: imageData,
                mimeType: 'image/png'
            });
        }
      } catch (e) {
        setError(`Failed to generate character ${character.name}`);
      }
      setLoadingSlots(prev => ({ ...prev, [characterId]: false }));
  }, [characters, style]);

  const handleSuggestSinglePrompt = useCallback(async (index: number) => {
    setIsSuggesting(true);
    try {
        const activeCharNames = characters.filter(c => promptActiveCharacterIds.includes(c.id)).map(c => c.name);
        const newPrompt = await suggestCreativePrompt({
            storyName,
            seriesName,
            characters: characters.map(c => c.name),
            activeCharacters: activeCharNames,
            existingPrompts: prompts,
            synopsis
        });
        const newPrompts = [...prompts];
        newPrompts[index] = newPrompt;
        setPrompts(newPrompts);
    } catch (e) {
        setError("Failed to suggest scene.");
    } finally {
        setIsSuggesting(false);
    }
  }, [characters, promptActiveCharacterIds, storyName, seriesName, prompts, synopsis]);

  const handleSuggestBulkPrompts = useCallback(async () => {
    setIsSuggesting(true);
    try {
        const emptyIndices = prompts.map((p, i) => p.trim() === '' ? i : -1).filter(i => i !== -1);
        if (emptyIndices.length === 0) return;

        const activeCharNames = characters.filter(c => promptActiveCharacterIds.includes(c.id)).map(c => c.name);
        const suggested = await suggestBulkScenes({
            storyName,
            seriesName,
            activeCharacters: activeCharNames,
            synopsis,
            count: emptyIndices.length,
            existingScenes: prompts
        });

        const newPrompts = [...prompts];
        emptyIndices.forEach((targetIdx, i) => {
            if (suggested[i]) newPrompts[targetIdx] = suggested[i];
        });
        setPrompts(newPrompts);
    } catch (e) {
        setError("Failed to populate scenes.");
    } finally {
        setIsSuggesting(false);
    }
  }, [characters, promptActiveCharacterIds, storyName, seriesName, prompts, synopsis]);

  const handleGenerateSynopsis = async () => {
    setIsLoading(true);
    const chars = characters.filter(c => c.isSelected).map(c => c.name);
    const result = await generateSynopsis(chars);
    setSynopsis(result);
    setIsLoading(false);
  };

  const handleEnhanceSynopsis = async () => {
    setIsLoading(true);
    const chars = characters.filter(c => c.isSelected).map(c => c.name);
    const result = await enhanceSynopsis(synopsis, chars);
    setSynopsis(result);
    setIsLoading(false);
  };

  return (
    <div className="min-h-screen bg-black font-sans flex flex-col overflow-hidden">
      <Header />

      <div className="flex-1 flex flex-col">
        {/* TOP: Results Display */}
        <div className="h-1/2 overflow-y-auto border-b border-gray-800">
            <ResultsDisplay 
                images={generatedImages} 
                isLoading={isLoading} 
                error={error} 
                storyName={storyName}
                seriesName={seriesName}
                onPreview={setPreviewImage}
            />
        </div>

        {/* BOTTOM: Generations Setting */}
        <div className="h-1/2 bg-gray-900 overflow-y-auto">
            <ControlPanel
              characters={characters}
              loadingSlots={loadingSlots}
              onUpdateCharacter={handleUpdateCharacter}
              onGenerateCharacter={handleGenerateCharacter}
              style={style}
              setStyle={setStyle}
              aspectRatio={aspectRatio}
              setAspectRatio={setAspectRatio}
              styleLocked={styleLocked}
              setStyleLocked={setStyleLocked}
              aspectRatioLocked={aspectRatioLocked}
              setAspectRatioLocked={setAspectRatioLocked}
              prompts={prompts}
              setPrompts={setPrompts}
              onGenerateAll={handleGenerateAll}
              onSuggestPrompt={handleSuggestBulkPrompts}
              onSuggestSinglePrompt={handleSuggestSinglePrompt}
              promptActiveCharacterIds={promptActiveCharacterIds}
              setPromptActiveCharacterIds={setPromptActiveCharacterIds}
              isLoading={isLoading}
              isSuggesting={isSuggesting}
              storyName={storyName}
              setStoryName={setStoryName}
              seriesName={seriesName}
              setSeriesName={setSeriesName}
              synopsis={synopsis}
              setSynopsis={setSynopsis}
              onGenerateSynopsis={handleGenerateSynopsis}
              onEnhanceSynopsis={handleEnhanceSynopsis}
            />
        </div>
      </div>

      {previewImage && (
        <div 
          className="fixed inset-0 bg-black/90 flex items-center justify-center z-50 p-4 backdrop-blur-md"
          onClick={() => setPreviewImage(null)}
        >
          <div className="relative max-w-4xl max-h-[90vh] bg-gray-900 p-2 rounded-2xl shadow-2xl border border-bee-gold/20" onClick={e => e.stopPropagation()}>
             <img src={`data:image/png;base64,${previewImage}`} alt="Preview" className="max-w-full max-h-[85vh] object-contain rounded-xl"/>
             <button
                onClick={() => setPreviewImage(null)}
                className="absolute -top-4 -right-4 bg-bee-gold text-black rounded-full p-2 hover:bg-bee-amber transition-transform shadow-lg"
              >
               <XIcon />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Character, ImageStyle, AspectRatio } from '../types';
import { CharacterSlot } from './CharacterSlot';
import { PlusIcon } from './icons/PlusIcon';
import { TrashIcon } from './icons/TrashIcon';
import { SparklesIcon } from './icons/SparklesIcon';

interface ControlPanelProps {
  characters: Character[];
  loadingSlots: Record<number, boolean>;
  onUpdateCharacter: (character: Character) => void;
  onGenerateCharacter: (characterId: number) => void;
  style: ImageStyle;
  setStyle: (style: ImageStyle) => void;
  aspectRatio: AspectRatio;
  setAspectRatio: (ratio: AspectRatio) => void;
  styleLocked: boolean;
  setStyleLocked: (l: boolean) => void;
  aspectRatioLocked: boolean;
  setAspectRatioLocked: (l: boolean) => void;
  prompts: string[];
  setPrompts: (prompts: string[]) => void;
  onGenerateAll: () => void;
  onSuggestPrompt: () => void;
  onSuggestSinglePrompt: (index: number) => void;
  promptActiveCharacterIds: number[];
  setPromptActiveCharacterIds: (ids: number[]) => void;
  isLoading: boolean;
  isSuggesting: boolean;
  storyName: string;
  setStoryName: (name: string) => void;
  seriesName: string;
  setSeriesName: (name: string) => void;
  synopsis: string;
  setSynopsis: (s: string) => void;
  onGenerateSynopsis: () => void;
  onEnhanceSynopsis: () => void;
}

type Tab = 'General' | 'Output' | 'Cast' | 'Scenes';

export const ControlPanel: React.FC<ControlPanelProps> = (props) => {
    const {
        characters, loadingSlots, onUpdateCharacter, onGenerateCharacter, style, setStyle, aspectRatio, setAspectRatio,
        styleLocked, setStyleLocked, aspectRatioLocked, setAspectRatioLocked,
        prompts, setPrompts, onGenerateAll, onSuggestPrompt, onSuggestSinglePrompt,
        promptActiveCharacterIds, setPromptActiveCharacterIds,
        isLoading, isSuggesting,
        storyName, setStoryName, seriesName, setSeriesName,
        synopsis, setSynopsis, onGenerateSynopsis, onEnhanceSynopsis
    } = props;

  const [activeTab, setActiveTab] = useState<Tab>('General');

  const handleAddPrompt = () => {
    if (prompts.length < 20) {
      setPrompts([...prompts, '']);
    }
  };

  const handleRemovePrompt = (index: number) => {
    setPrompts(prompts.filter((_, i) => i !== index));
  };

  const handlePromptChange = (index: number, value: string) => {
    const newPrompts = [...prompts];
    newPrompts[index] = value;
    setPrompts(newPrompts);
  };

  const togglePromptActiveChar = (id: number) => {
      if (promptActiveCharacterIds.includes(id)) {
          setPromptActiveCharacterIds(promptActiveCharacterIds.filter(i => i !== id));
      } else {
          setPromptActiveCharacterIds([...promptActiveCharacterIds, id]);
      }
  };

  return (
    <div className="flex flex-col h-full bg-black">
      {/* Mobile Render Button Section */}
      <div className="md:hidden p-4 border-b border-gray-800">
        <button
            onClick={onGenerateAll}
            disabled={isLoading}
            style={{ backgroundColor: '#55DDE0' }}
            className="w-full text-black font-black text-sm py-3 rounded-full hover:brightness-110 transition-all disabled:opacity-50 uppercase tracking-widest shadow-lg"
        >
            {isLoading ? 'RENDERING...' : 'RENDER'}
        </button>
      </div>

      {/* Tab Headers - Compact for all devices to fit on one row */}
      <div className="flex border-b border-gray-800 bg-gray-950 overflow-x-hidden sticky top-0 z-20">
        {[
          { id: 'General', label: 'General' },
          { id: 'Output', label: 'Output' },
          { id: 'Cast', label: 'Cast' },
          { id: 'Scenes', label: 'Scenes' }
        ].map(t => (
          <button
            key={t.id}
            onClick={() => setActiveTab(t.id as Tab)}
            className={`flex-1 px-2 py-4 text-[9px] md:text-sm font-black uppercase tracking-[0.15em] md:tracking-widest transition-all whitespace-nowrap text-center ${
              activeTab === t.id 
                ? 'text-bee-gold border-b-2 border-bee-gold' 
                : 'text-gray-500 hover:text-gray-300'
            }`}
          >
            {t.label}
          </button>
        ))}
        {/* Desktop RENDER Button */}
        <div className="hidden md:flex ml-auto items-center pr-6">
            <button
                onClick={onGenerateAll}
                disabled={isLoading}
                style={{ backgroundColor: '#55DDE0' }}
                className="text-black font-black text-[10px] px-8 py-2 rounded-full hover:brightness-110 transition-all disabled:opacity-50 uppercase tracking-widest"
            >
                {isLoading ? 'RENDERING...' : 'RENDER'}
            </button>
        </div>
      </div>

      {/* Tab Content */}
      <div className="flex-1 p-4 md:p-8 overflow-y-auto overflow-x-hidden">
        {activeTab === 'General' && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-5xl mx-auto">
            <div className="space-y-6">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black uppercase text-gray-500 mb-1 tracking-widest">Series Name</label>
                  <input value={seriesName} onChange={e => setSeriesName(e.target.value)} className="w-full bg-gray-900 border border-gray-800 rounded px-3 py-2 text-sm focus:ring-1 focus:ring-bee-gold outline-none"/>
                </div>
                <div>
                  <label className="block text-[10px] font-black uppercase text-gray-500 mb-1 tracking-widest">Story Name</label>
                  <input value={storyName} onChange={e => setStoryName(e.target.value)} className="w-full bg-gray-900 border border-gray-800 rounded px-3 py-2 text-sm focus:ring-1 focus:ring-bee-gold outline-none"/>
                </div>
              </div>
            </div>
            <div className="space-y-3">
                <label className="block text-[10px] font-black uppercase text-gray-500 mb-1 tracking-widest">Synopsis</label>
                <textarea 
                    value={synopsis} 
                    onChange={e => setSynopsis(e.target.value.slice(0, 1500))} 
                    rows={6}
                    className="w-full bg-gray-900 border border-gray-800 rounded px-3 py-2 text-sm focus:ring-1 focus:ring-bee-gold outline-none resize-none leading-relaxed"
                    placeholder="Enter the overall narrative direction..."
                />
                <div className="flex flex-wrap gap-2">
                    <button onClick={onGenerateSynopsis} className="flex-1 min-w-fit px-4 py-2 bg-gray-800 text-[9px] font-black rounded hover:bg-gray-700 transition-colors uppercase tracking-widest">GENERATE STORYLINE</button>
                    <button onClick={onEnhanceSynopsis} className="flex-1 min-w-fit px-4 py-2 bg-gray-800 text-[9px] font-black rounded hover:bg-gray-700 transition-colors uppercase tracking-widest">ENHANCE STORY</button>
                </div>
            </div>
          </div>
        )}

        {activeTab === 'Output' && (
          <div className="flex flex-col md:flex-row gap-8 md:gap-12 max-w-4xl mx-auto items-start">
             <div className="space-y-4 w-full md:w-1/2">
                <div className="flex items-center justify-between">
                    <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest">Image Style</label>
                    <button onClick={() => setStyleLocked(!styleLocked)} className={`text-[10px] font-black ${styleLocked ? 'text-bee-gold' : 'text-gray-600'}`}>
                        {styleLocked ? 'LOCKED' : 'LOCK'}
                    </button>
                </div>
                <select 
                    disabled={styleLocked}
                    value={style} 
                    onChange={e => setStyle(e.target.value as ImageStyle)} 
                    className="w-full bg-gray-900 border border-gray-800 rounded px-3 py-2 text-sm focus:ring-1 focus:ring-bee-gold outline-none"
                >
                    {Object.values(ImageStyle).map(s => <option key={s} value={s}>{s}</option>)}
                </select>
             </div>
             <div className="space-y-4 w-full md:w-1/2">
                <div className="flex items-center justify-between">
                    <label className="block text-[10px] font-black uppercase text-gray-500 tracking-widest">Aspect Ratio</label>
                    <button onClick={() => setAspectRatioLocked(!aspectRatioLocked)} className={`text-[10px] font-black ${aspectRatioLocked ? 'text-bee-gold' : 'text-gray-600'}`}>
                        {aspectRatioLocked ? 'LOCKED' : 'LOCK'}
                    </button>
                </div>
                <select 
                    disabled={aspectRatioLocked}
                    value={aspectRatio} 
                    onChange={e => setAspectRatio(e.target.value as AspectRatio)} 
                    className="w-full bg-gray-900 border border-gray-800 rounded px-3 py-2 text-sm focus:ring-1 focus:ring-bee-gold outline-none"
                >
                    {Object.values(AspectRatio).map(r => <option key={r} value={r}>{r}</option>)}
                </select>
             </div>
          </div>
        )}

        {activeTab === 'Cast' && (
          <div className="grid grid-cols-2 md:flex md:overflow-x-auto gap-4 pb-4 px-1 no-scrollbar max-w-7xl mx-auto">
            {characters.map(char => (
                <div key={char.id} className="w-full md:min-w-[200px]">
                    <CharacterSlot 
                        character={char} 
                        isLoading={loadingSlots[char.id]}
                        onUpdate={onUpdateCharacter} 
                        onGenerate={onGenerateCharacter} 
                    />
                </div>
            ))}
          </div>
        )}

        {activeTab === 'Scenes' && (
          <div className="max-w-6xl mx-auto space-y-8">
            {/* Active Characters Sub-window */}
            <div className="bg-gray-950/50 p-4 rounded-xl border border-gray-800">
                <h3 className="text-[10px] font-black uppercase text-gray-500 tracking-widest mb-4">Select Active Characters for Next Generation</h3>
                <div className="flex flex-wrap gap-2">
                    {characters.map(c => (
                        <button
                            key={c.id}
                            onClick={() => togglePromptActiveChar(c.id)}
                            className={`px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-tighter transition-all border ${
                                promptActiveCharacterIds.includes(c.id)
                                    ? 'bg-bee-gold text-black border-bee-gold'
                                    : 'bg-transparent text-gray-500 border-gray-800 hover:border-gray-600'
                            }`}
                        >
                            {c.name}
                        </button>
                    ))}
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-4">
                {prompts.map((prompt, index) => (
                    <div key={index} className="flex items-start space-x-3 bg-gray-950 p-3 rounded-lg border border-gray-800 hover:border-gray-700 transition-colors group relative">
                        <span className="text-bee-gold font-black text-[10px] mt-2 w-5">{String(index + 1).padStart(2, '0')}</span>
                        <textarea
                            value={prompt}
                            onChange={e => handlePromptChange(index, e.target.value)}
                            rows={2}
                            className="flex-grow bg-transparent text-sm focus:outline-none resize-none placeholder-gray-800"
                            placeholder="Describe the action..."
                        />
                        <div className="flex flex-col space-y-2 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button 
                                onClick={() => onSuggestSinglePrompt(index)} 
                                disabled={isSuggesting}
                                className="p-1.5 text-bee-gold/50 hover:text-bee-gold transition-colors" 
                                title="Magic Prompt"
                            >
                                <SparklesIcon className={`w-3.5 h-3.5 ${isSuggesting ? 'animate-pulse' : ''}`} />
                            </button>
                            <button 
                                onClick={() => handleRemovePrompt(index)} 
                                className="p-1.5 text-gray-700 hover:text-red-500 transition-colors" 
                                title="Remove"
                            >
                                <TrashIcon className="w-3.5 h-3.5" />
                            </button>
                        </div>
                    </div>
                ))}
            </div>

            <div className="flex flex-col sm:flex-row justify-center items-center gap-4 mt-8 pb-10">
                {prompts.length < 20 && (
                    <button 
                        onClick={handleAddPrompt} 
                        className="w-full sm:w-auto flex items-center justify-center space-x-2 py-3 px-10 border border-gray-800 rounded-full text-gray-500 hover:text-white hover:border-gray-600 transition-all text-[10px] font-black uppercase tracking-widest"
                    >
                        <PlusIcon className="w-3.5 h-3.5" />
                        <span>Add Scene</span>
                    </button>
                )}
                <button 
                    onClick={onSuggestPrompt}
                    disabled={isSuggesting || promptActiveCharacterIds.length === 0}
                    className="w-full sm:w-auto flex items-center justify-center space-x-2 py-3 px-10 bg-bee-gold/5 border border-bee-gold/20 text-bee-gold rounded-full hover:bg-bee-gold/10 transition-all text-[10px] font-black uppercase tracking-widest disabled:opacity-30"
                >
                    {isSuggesting ? (
                        <div className="w-3.5 h-3.5 border-2 border-bee-gold border-t-transparent rounded-full animate-spin"></div>
                    ) : (
                        <SparklesIcon className="w-3.5 h-3.5" />
                    )}
                    <span>Populate Scenes</span>
                </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React from 'react';
import { GeneratedImageResult } from '../types';
import { DownloadIcon } from './icons/DownloadIcon';
import { PreviewIcon } from './icons/PreviewIcon';

interface ResultsDisplayProps {
  images: GeneratedImageResult[];
  isLoading: boolean;
  error: string | null;
  storyName: string;
  seriesName: string;
  onPreview: (imageData: string) => void;
}

const downloadImage = (imageData: string, filename: string) => {
    const link = document.createElement('a');
    link.href = `data:image/png;base64,${imageData}`;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
};

export const ResultsDisplay: React.FC<ResultsDisplayProps> = ({ images, isLoading, error, storyName, seriesName, onPreview }) => {

  const handleDownloadAll = () => {
    images.forEach((img) => {
        const filename = `Scene${img.sceneIndex}_${storyName}_${seriesName}.png`;
        downloadImage(img.imageData, filename);
    });
  };

  return (
    <section className="p-6 h-full">
      <div className="flex justify-between items-center mb-6 sticky top-0 bg-black/80 backdrop-blur-md z-10 py-2">
        <div className="flex items-center space-x-4">
            <h1 className="text-xl font-black uppercase tracking-tighter text-bee-gold">Render Output</h1>
            {isLoading && (
                <div className="flex items-center space-x-2 text-[10px] font-bold text-bee-gold animate-pulse">
                    <div className="w-1.5 h-1.5 rounded-full bg-bee-gold"></div>
                    <span>PROCESSING SEQUENCE...</span>
                </div>
            )}
        </div>
        {images.length > 0 && (
          <button 
            onClick={handleDownloadAll}
            className="text-[10px] font-black uppercase tracking-widest border border-bee-gold text-bee-gold px-4 py-1.5 rounded-full hover:bg-bee-gold hover:text-black transition-all flex items-center space-x-2"
          >
            <DownloadIcon className="w-3 h-3" />
            <span>Export Batch</span>
          </button>
        )}
      </div>

      {error && (
        <div className="bg-red-950/30 border border-red-900/50 text-red-500 text-[10px] font-bold uppercase tracking-widest px-4 py-3 rounded mb-4">
          Error: {error}
        </div>
      )}

      {images.length === 0 && !isLoading && (
         <div className="flex items-center justify-center h-48 text-center text-gray-700 border-2 border-dashed border-gray-900 rounded-2xl">
            <p className="text-xs font-bold uppercase tracking-[0.2em]">Ready for Narrative Input</p>
        </div>
      )}

      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-6">
        {images.map((img) => {
            const filename = `Scene${img.sceneIndex}_${storyName}_${seriesName}.png`;
          return (
            <div key={img.id} className="group relative aspect-square bg-gray-950 rounded-xl overflow-hidden shadow-2xl border border-gray-900 hover:border-bee-gold/40 transition-all">
                <img src={`data:image/png;base64,${img.imageData}`} alt={img.prompt} className="w-full h-full object-cover"/>
                <div className="absolute bottom-2 left-2 bg-black/60 backdrop-blur-md px-2 py-0.5 rounded text-[8px] font-black text-white/70">
                    S-{img.sceneIndex}
